query:
SELECT COUNT(*) as total_roles FROM cpa_supervision_roles WHERE is_active = 1;
SELECT COUNT(*) as total_baseline FROM cpa_supervision_baseline;
SELECT sr.code, sr.label, sr.monthly_rate_aed FROM cpa_supervision_roles sr ORDER BY sr.sort_order LIMIT 10;

